/* Environment tag */
.env-banner {
    position: fixed;
    top: 0;
    left: 50%;
    transform: translateX(-50%);
    padding: 8px 16px;
    font-weight: 700;
    font-size: 13px;
    letter-spacing: 0.05em;
    text-transform: uppercase;
    text-align: center;
    color: #fff;
    z-index: 500;
    width: auto;
    max-width: 90vw;
    background-color: brown;
    border-radius: 0px 0px 4px 4px;
    box-shadow: 0 5px 15px rgba(0, 0, 0, 0.3);
    display: flex;
    align-items: center;
    gap: 12px;
    transition: transform 0.3s ease;
}

.env-banner--hidden {
    transform: translateX(-50%) translateY(-100%);
}

.env-banner__close {
    background: rgba(255, 255, 255, 0.2);
    border: none;
    color: #fff;
    font-size: 20px;
    line-height: 1;
    width: 24px;
    height: 24px;
    border-radius: 3px;
    cursor: pointer;
    padding: 0;
    transition: background 0.2s;
}

.env-banner__close:hover {
    background: rgba(255, 255, 255, 0.3);
}

.env-banner__restore {
    position: fixed;
    top: 0;
    left: 50%;
    transform: translateX(-50%) translateY(-100%);
    background: rgba(0, 0, 0, 0.6);
    border: none;
    color: #fff;
    font-size: 16px;
    padding: 4px 12px;
    border-radius: 0px 0px 4px 4px;
    cursor: pointer;
    z-index: 499;
    transition: transform 0.3s ease;
}

.env-banner__restore--visible {
    transform: translateX(-50%) translateY(0);
}

.env-banner__restore:hover {
    background: rgba(0, 0, 0, 0.8);
}

.env-banner--local {
    background: #b71c1c;
}

.env-banner--staging {
    background: #f57c00;
}

